seed.query:
query OrderEditQuantityValidationSeed($first: Int!) {
    locations(first: 10) {
      nodes {
        id
        name
        isActive
      }
    }
    products(first: $first) {
      nodes {
        id
        title
        variants(first: 5) {
          nodes {
            id
            title
            sku
            price
            product {
              id
              title
            }
          }
        }
      }
    }
  }

orderCreate.query:
#graphql
  fragment OrderEditQuantityValidationOrderFields on Order {
    id
    name
    email
    note
    tags
    createdAt
    updatedAt
    cancelledAt
    displayFinancialStatus
    displayFulfillmentStatus
    presentmentCurrencyCode
    currentSubtotalLineItemsQuantity
    currentSubtotalPriceSet {
      shopMoney {
        amount
        currencyCode
      }
      presentmentMoney {
        amount
        currencyCode
      }
    }
    currentTotalPriceSet {
      shopMoney {
        amount
        currencyCode
      }
      presentmentMoney {
        amount
        currencyCode
      }
    }
    lineItems(first: 10) {
      nodes {
        id
        title
        name
        quantity
        currentQuantity
        sku
        variantTitle
        originalUnitPriceSet {
          shopMoney {
            amount
            currencyCode
          }
          presentmentMoney {
            amount
            currencyCode
          }
        }
        variant {
          id
          title
          sku
        }
      }
    }
  }

  mutation OrderEditQuantityValidationCreate($order: OrderCreateOrderInput!, $options: OrderCreateOptionsInput) {
    orderCreate(order: $order, options: $options) {
      order {
        ...OrderEditQuantityValidationOrderFields
      }
      userErrors {
        field
        message
      }
    }
  }

